1	type Item = { type: string; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const FIRST_INSURANCE_MULTIPLIER = 1.1;
6	const CURSED_MULTIPLIER = 1.5;
7	const ADMIN_FEE = 5;
8	
9	const BASE_PRICE: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	};
15	
16	export function runScenario(scenario: unknown): unknown {
17	  const { steps } = scenario as Scenario;
18	  const item = steps[0].items[0];
19	  const cursedMultiplier = item.cursed ? CURSED_MULTIPLIER : 1;
20	  const itemBase = BASE_PRICE[item.type] * cursedMultiplier;
21	  const premium = Math.round(itemBase * FIRST_INSURANCE_MULTIPLIER) + ADMIN_FEE;
22	  return { results: [{ premium }] };
23	}
